{"command": "$email='3479762521@qq.com';
$localState="$env:LOCALAPPDATA\Microsoft\Edge\User Data\Local State";
function Find-EmailPath($obj, $path){
  if($null -eq $obj){ return }
  if($obj -is [string]){ if($obj -like "*$email*"){ Write-Output "$path = $obj" }; return }
  if($obj -is [System.Collections.IEnumerable] -and -not ($obj -is [string]) -and -not ($obj -is [System.Management.Automation.PSCustomObject])){
    $i=0; foreach($item in $obj){ Find-EmailPath $item "$path[$i]"; $i++ }; return
  }
  if($obj -is [System.Management.Automation.PSCustomObject]){
    foreach($prop in $obj.PSObject.Properties){ Find-EmailPath $prop.Value "$path.$($prop.Name)" }
  }
}
if(Test-Path $localState){
  $json=Get-Content -LiteralPath $localState -Raw | ConvertFrom-Json;
  Find-EmailPath $json '$'
}", "workdir": "D:\daily-stock-analysis-windows-noinstall-v3.24.1\win-unpacked", "timeout_ms": 30000}

