{"command":"$email='3479762521@qq.com'
$stamp=Get-Date -Format 'yyyyMMdd-HHmmss'
$backupRoot=Join-Path $env:USERPROFILE "Desktop\edge-email-cleanup-backup-$stamp"
New-Item -ItemType Directory -Path $backupRoot -Force | Out-Null

# Edge Local State: remove only the matching signout account entry.
$localState="$env:LOCALAPPDATA\Microsoft\Edge\User Data\Local State"
if(Test-Path $localState){
  Copy-Item -LiteralPath $localState -Destination (Join-Path $backupRoot 'Edge-Local-State.backup') -Force
  $json=Get-Content -LiteralPath $localState -Raw | ConvertFrom-Json
  if($json.profiles -and $json.profiles.signout_accounts){
    $json.profiles.signout_accounts = @($json.profiles.signout_accounts | Where-Object { $_.user_name -ne $email })
    $json | ConvertTo-Json -Depth 100 -Compress | Set-Content -LiteralPath $localState -Encoding UTF8
  }
}

# Windows Microsoft account registry cache.
$regPath="HKCU:\Software\Microsoft\IdentityCRL\UserExtendedProperties\$email"
if(Test-Path $regPath){
  reg export "HKCU\Software\Microsoft\IdentityCRL\UserExtendedProperties\$email" (Join-Path $backupRoot 'IdentityCRL-user.reg') /y | Out-Null
  Remove-Item -LiteralPath $regPath -Recurse -Force
}

# OneAuth cache files containing the email.
$one="$env:LOCALAPPDATA\Microsoft\OneAuth"
if(Test-Path $one){
  Get-ChildItem -LiteralPath $one -Recurse -Force -File -ErrorAction SilentlyContinue |
    Where-Object { $_.Length -lt 20MB } |
    Select-String -SimpleMatch $email -List -ErrorAction SilentlyContinue |
    ForEach-Object {
      $src=$_.Path
      $safeName=($src -replace '^[A-Za-z]:','' -replace '[\\/:*?"<>|]','_')
      Copy-Item -LiteralPath $src -Destination (Join-Path $backupRoot $safeName) -Force
      Remove-Item -LiteralPath $src -Force
    }
}

# IE/WinINet cache files containing the email.
$inet="$env:LOCALAPPDATA\Microsoft\Windows\INetCache"
if(Test-Path $inet){
  Get-ChildItem -LiteralPath $inet -Recurse -Force -File -ErrorAction SilentlyContinue |
    Where-Object { $_.Length -lt 20MB } |
    Select-String -SimpleMatch $email -List -ErrorAction SilentlyContinue |
    ForEach-Object {
      $src=$_.Path
      $safeName=($src -replace '^[A-Za-z]:','' -replace '[\\/:*?"<>|]','_')
      Copy-Item -LiteralPath $src -Destination (Join-Path $backupRoot $safeName) -Force
      Remove-Item -LiteralPath $src -Force
    }
}

Write-Output "BACKUP_ROOT`t$backupRoot"","workdir":"D:\daily-stock-analysis-windows-noinstall-v3.24.1\win-unpacked","timeout_ms":30000}

